exercises.solution_code:
#include <iostream>
#include <random>

int main() {
    unsigned int seedA{}, seedB{};
    std::cin >> seedA >> seedB;

    std::mt19937 rngA{ seedA };
    std::mt19937 rngB{ seedB };

    std::uniform_int_distribution<int> dist{ 1, 100 };

    bool same{ true };
    for (int i{ 0 }; i < 5; ++i) {
        int a{ dist(rngA) };
        int b{ dist(rngB) };
        if (a != b)
            same = false;
    }

    if (same)
        std::cout << "Same sequence\n";
    else
        std::cout << "Different sequences\n";

    return 0;
}

