exercises.solution_code:
#include <iostream>
#include <random>

int main() {
    unsigned int seed{};
    int lo{}, hi{}, n{};
    std::cin >> seed >> lo >> hi >> n;

    std::mt19937 rng{ seed };
    std::uniform_int_distribution<int> dist{ lo, hi };

    bool allInRange{ true };

    for (int i{ 0 }; i < n; ++i) {
        int value{ dist(rng) };
        if (value < lo || value > hi)
            allInRange = false;
    }

    std::cout << "Generated: " << n << " values\n";
    if (allInRange)
        std::cout << "All in range: yes\n";
    else
        std::cout << "All in range: no\n";

    return 0;
}
